// Assemble the gpt-image-2 EDIT prompt for the article poster.
// The master template (fetched from the immutable library URL the API sends as
// reference_url) already carries a BAKED-IN Marathi headline and a BAKED-IN
// farmer photo — this is an EDIT that REPLACES both, not an add-on. Keep the महासंवाद logo card, the orange left panel
// and the navy + white footer bands exactly; swap in ONE new Marathi headline and a
// new background photo from scene_brief. Deliberately simple: one headline, no
// bullets/stats/quotes — visually distinct from the multi-element social posters.
const src = $input.first().json;
const headline = (src.headline || '').toString().trim();
const scene_brief = (src.scene_brief || '').toString().trim();
const reference_url = (src.reference_url || '').toString().trim();
if (!headline) { throw new Error('No "headline" received in the webhook body.'); }
// Fail loud rather than editing a stale canonical master: the API must send the
// enabled article master's immutable library URL.
if (!reference_url) { throw new Error('No "reference_url" received in the webhook body — the API must send the enabled article master URL.'); }

const prompt = [
  'You are editing an OFFICIAL DGIPR Maharashtra government ARTICLE poster: a single landscape banner.',
  'KEEP the master template EXACTLY as provided — same overall layout and proportions, the महासंवाद logo card in the top-left, the curved orange left panel, the navy department footer band that reads "माहिती व जनसंपर्क महासंचालनालय, महाराष्ट्र शासन", and the white social-handle strip along the very bottom. Do NOT move, restyle, recolour, remove or duplicate any of these framing elements, and do not change the footer text.',
  '',
  'REPLACE only these two things, inside the master\'s existing zones:',
  '',
  '1) HEADLINE — erase the existing Marathi headline on the orange left panel and typeset THIS headline in its place, spelled EXACTLY as given, in correct Devanagari (Marathi). Dark maroon (#7a1512), bold (weight 900), centered on the orange panel, large and crisply legible. This is the ONLY text you add anywhere on the poster.',
  'HEADLINE (verbatim, do not translate or alter): ' + headline,
  '',
  '2) PHOTO — erase the existing farmer photo and fill the right-hand curved photo zone with a NEW realistic documentary photograph matching the description below. Keep the human subject on the RIGHT and a calmer, less-busy LEFT third so the headline panel stays fully readable. The photo must contain NO text, words, letters, numbers or logos.',
  'PHOTO (background imagery only): ' + (scene_brief || 'a relevant Maharashtra public-welfare documentary scene'),
  '',
  'Add NO other text: no subhead, no bullet points, no statistics, no quotes, no extra logos, no captions, and no outer border. Output ONE complete poster filling the whole canvas.',
].join('\n');

return [{ json: { prompt, headline, scene_brief, reference_url, generation_id: src.generation_id } }];
